import{_ as t,o,c as a,h as i}from"./chunks/framework.3WqHSPpF.js";const u=JSON.parse('{"title":"Token Structure","description":"","frontmatter":{},"headers":[],"relativePath":"tokens/structure.md","filePath":"tokens/structure.md"}'),s={name:"tokens/structure.md"};function n(l,e,r,d,c,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="token-structure" tabindex="-1">Token Structure <a class="header-anchor" href="#token-structure" aria-label="Permalink to &quot;Token Structure&quot;">​</a></h1><p>This page explains how Cobalt tokens are organized and how to decide where a token belongs.</p><p>For designers working in Figma, the main idea is simple:</p><ul><li><strong>Primitives</strong> are raw ingredients</li><li><strong>Semantic tokens</strong> describe design intent</li><li><strong>Theme tokens</strong> change that intent by theme or mode</li><li><strong>Component tokens</strong> are reserved for true component-specific needs</li></ul><h2 id="the-five-layers" tabindex="-1">The Five Layers <a class="header-anchor" href="#the-five-layers" aria-label="Permalink to &quot;The Five Layers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>What it means</th><th>Use it for</th><th>Examples</th></tr></thead><tbody><tr><td><code>primitives.json</code></td><td>Raw foundational values</td><td>Spacing scale, radius scale, type scale, motion values, breakpoints</td><td><code>space.4</code>, <code>shape.radius.sm</code>, <code>font.size.md</code></td></tr><tr><td><code>primitives.color.json</code></td><td>Raw color palette</td><td>Neutral and brand ramps</td><td><code>neutral.100</code>, <code>blue.500</code>, <code>red.600</code></td></tr><tr><td><code>semantic.shared.json</code></td><td>Shared design decisions that stay the same across themes</td><td>Control sizing, focus rules, shared layout values</td><td><code>control.height.md</code>, <code>control.radius</code>, <code>focus.ring.width</code></td></tr><tr><td><code>semantic.theme.&lt;theme&gt;.&lt;mode&gt;.json</code></td><td>Semantic tokens that change by theme or mode</td><td>Mostly color behavior today</td><td><code>color.text.default</code>, <code>color.surface.default</code>, <code>color.primary.base</code></td></tr><tr><td><code>components.json</code></td><td>Component-specific tokens</td><td>Public component contracts or intentional exceptions</td><td><code>component.avatar.size.md</code></td></tr></tbody></table><h2 id="why-the-five-layers" tabindex="-1">Why The Five Layers <a class="header-anchor" href="#why-the-five-layers" aria-label="Permalink to &quot;Why The Five Layers&quot;">​</a></h2><p>The five layer structure separates:</p><ol><li>raw values</li><li>shared system rules</li><li>theme-specific changes</li><li>component-specific exceptions</li></ol><p>This makes the token system easier to scale as more themes are added and easier to understand in Figma handoff.</p><h2 id="what-this-means-in-practice" tabindex="-1">What This Means In Practice <a class="header-anchor" href="#what-this-means-in-practice" aria-label="Permalink to &quot;What This Means In Practice&quot;">​</a></h2><h3 id="_1-primitives-are-not-design-decisions" tabindex="-1">1. Primitives are not design decisions <a class="header-anchor" href="#_1-primitives-are-not-design-decisions" aria-label="Permalink to &quot;1. Primitives are not design decisions&quot;">​</a></h3><p>Primitives are the building blocks.</p><p>Examples:</p><ul><li><code>font.size.md</code></li><li><code>space.4</code></li><li><code>shape.radius.sm</code></li><li><code>blue.500</code></li></ul><p>These values exist so the system has a consistent base scale, but they do not explain how the value should be used.</p><h3 id="_2-shared-semantics-describe-the-system-s-rules" tabindex="-1">2. Shared semantics describe the system&#39;s rules <a class="header-anchor" href="#_2-shared-semantics-describe-the-system-s-rules" aria-label="Permalink to &quot;2. Shared semantics describe the system&#39;s rules&quot;">​</a></h3><p><code>semantic.shared.json</code> is where we store design intent that should stay consistent across the whole system.</p><p>Examples:</p><ul><li><code>focus.ring.width</code></li><li><code>focus.ring.offset</code></li><li><code>control.height.md</code></li><li><code>control.radius</code></li><li><code>layout.content.max-width.lg</code></li></ul><p>These tokens answer questions like:</p><ul><li>How tall is a medium control?</li><li>What radius should standard controls use?</li><li>How wide should shared content containers be?</li></ul><h3 id="_3-theme-files-only-hold-what-changes-by-theme" tabindex="-1">3. Theme files only hold what changes by theme <a class="header-anchor" href="#_3-theme-files-only-hold-what-changes-by-theme" aria-label="Permalink to &quot;3. Theme files only hold what changes by theme&quot;">​</a></h3><p><code>semantic.theme.&lt;theme&gt;.&lt;mode&gt;.json</code> is for semantic values that need to change when the theme changes.</p><p>Today, that is mostly color.</p><p>Examples:</p><ul><li><code>color.text.default</code></li><li><code>color.surface.raised</code></li><li><code>color.border.focus</code></li><li><code>color.interactive.default</code></li></ul><p>This keeps theme files focused and prevents shared rules like typography or spacing from being repeated in every theme.</p><h3 id="_4-component-tokens-stay-selective" tabindex="-1">4. Component tokens stay selective <a class="header-anchor" href="#_4-component-tokens-stay-selective" aria-label="Permalink to &quot;4. Component tokens stay selective&quot;">​</a></h3><p><code>components.json</code> is not meant to mirror the entire token system.</p><p>It exists for cases where a component has its own public sizing or behavior contract.</p><p>Example:</p><ul><li><code>component.avatar.size.sm</code></li><li><code>component.avatar.size.md</code></li><li><code>component.avatar.size.lg</code></li></ul><p>This keeps component tokens useful without creating token bloat.</p><h2 id="a-simple-decision-guide" tabindex="-1">A Simple Decision Guide <a class="header-anchor" href="#a-simple-decision-guide" aria-label="Permalink to &quot;A Simple Decision Guide&quot;">​</a></h2><p>When adding or reviewing a token, ask these questions in order:</p><h3 id="is-this-just-a-raw-value" tabindex="-1">Is this just a raw value? <a class="header-anchor" href="#is-this-just-a-raw-value" aria-label="Permalink to &quot;Is this just a raw value?&quot;">​</a></h3><p>If yes, it belongs in <code>primitives</code>.</p><p>Example:</p><ul><li>a new spacing step</li><li>a new radius</li><li>a new palette color</li></ul><h3 id="is-this-a-reusable-design-rule-across-the-system" tabindex="-1">Is this a reusable design rule across the system? <a class="header-anchor" href="#is-this-a-reusable-design-rule-across-the-system" aria-label="Permalink to &quot;Is this a reusable design rule across the system?&quot;">​</a></h3><p>If yes, it belongs in <code>semantic.shared</code>.</p><p>Example:</p><ul><li>default control height</li><li>default control radius</li><li>focus ring width</li><li>content max width</li></ul><h3 id="does-this-value-change-by-theme-or-mode" tabindex="-1">Does this value change by theme or mode? <a class="header-anchor" href="#does-this-value-change-by-theme-or-mode" aria-label="Permalink to &quot;Does this value change by theme or mode?&quot;">​</a></h3><p>If yes, it belongs in <code>semantic.theme.&lt;theme&gt;.&lt;mode&gt;</code>.</p><p>Example:</p><ul><li>text color in light vs dark</li><li>surface color in light vs dark</li><li>interactive color in different branded themes</li></ul><h3 id="is-this-specific-to-one-component" tabindex="-1">Is this specific to one component? <a class="header-anchor" href="#is-this-specific-to-one-component" aria-label="Permalink to &quot;Is this specific to one component?&quot;">​</a></h3><p>If yes, it belongs in <code>components</code>.</p><p>Example:</p><ul><li>avatar size</li><li>a unique component-only spacing rule</li><li>a component shape that should not become a system-wide standard</li></ul><h2 id="common-examples" tabindex="-1">Common Examples <a class="header-anchor" href="#common-examples" aria-label="Permalink to &quot;Common Examples&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Need</th><th>Best location</th><th>Why</th></tr></thead><tbody><tr><td>Focus ring width</td><td><code>semantic.shared</code></td><td>It is a shared interaction rule</td></tr><tr><td>Primary text color in dark mode</td><td><code>semantic.theme.default.dark</code></td><td>It changes by theme</td></tr><tr><td>Button and input height</td><td><code>semantic.shared</code></td><td>It is a shared control rule</td></tr><tr><td>Avatar sizes</td><td><code>components</code></td><td>It belongs to Avatar, not every control</td></tr><tr><td>New gray ramp</td><td><code>primitives.color</code></td><td>It is a raw palette</td></tr><tr><td>New radius scale step</td><td><code>primitives</code></td><td>It is a foundational value</td></tr></tbody></table><h2 id="about-the-control-section" tabindex="-1">About The <code>control</code> Section <a class="header-anchor" href="#about-the-control-section" aria-label="Permalink to &quot;About The `control` Section&quot;">​</a></h2><p>The <code>control</code> section is for shared rules used by standard interactive controls.</p><p>Examples:</p><ul><li>buttons</li><li>inputs</li><li>selects</li><li>segmented controls</li></ul><p>Current control tokens cover:</p><ul><li>height</li><li>radius</li></ul><p>This was added so controls feel related to each other instead of each component inventing its own sizing rules.</p><p>This section should <strong>not</strong> be used for:</p><ul><li>avatars</li><li>icons</li><li>cards</li><li>layout containers</li></ul><h2 id="recommended-figma-mindset" tabindex="-1">Recommended Figma Mindset <a class="header-anchor" href="#recommended-figma-mindset" aria-label="Permalink to &quot;Recommended Figma Mindset&quot;">​</a></h2><p>When working in Figma:</p><ul><li>use semantic tokens first</li><li>use primitives when you are building the underlying system</li><li>use theme tokens when reviewing light/dark or future brand theme behavior</li><li>use component tokens only for real component-specific contracts</li></ul><p>If a token feels like a system rule, it probably belongs in <code>semantic.shared</code>.</p><p>If it only makes sense for one component, it probably belongs in <code>components</code>.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./">Token Reference</a></li><li><a href="./../foundations/typography.html">Typography</a></li><li><a href="./../foundations/colors.html">Colors</a></li></ul>',70)])])}const p=t(s,[["render",n]]);export{u as __pageData,p as default};
